import{_ as t,o as s,c as e,a3 as n}from"./chunks/framework.CRbjHCyB.js";const m=JSON.parse('{"title":"命令树","description":"","frontmatter":{},"headers":[],"relativePath":"zh/catter/features/command-tree.md","filePath":"zh/catter/features/command-tree.md"}'),i={name:"zh/catter/features/command-tree.md"};function o(l,a,d,p,c,r){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="命令树" tabindex="-1">命令树 <a class="header-anchor" href="#命令树" aria-label="Permalink to &quot;命令树&quot;">​</a></h1><p>命令树将构建命令的有向无环图以 ASCII 树的形式可视化，展示进程之间的父子关系及其执行的命令。</p><p>内置脚本：<code>script::cmd-tree</code></p><h2 id="用法" tabindex="-1">用法 <a class="header-anchor" href="#用法" aria-label="Permalink to &quot;用法&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">catter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script::cmd-tree</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [options] -- </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build-command</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="选项" tabindex="-1">选项 <a class="header-anchor" href="#选项" aria-label="Permalink to &quot;选项&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td><code>-d, --depth &lt;n&gt;</code></td><td>限制渲染深度。</td></tr><tr><td><code>-a, --args &lt;n&gt;</code></td><td>每条命令显示的参数数量。默认：全部。</td></tr><tr><td><code>-w, --argWidth &lt;n&gt;</code></td><td>将过长的参数截断到指定宽度。默认：10 个字符。</td></tr></tbody></table><h2 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h2><p>输出为 ANSI 彩色的 ASCII 树，使用制表符（<code>│</code>、<code>├──</code>、<code>└──</code>）绘制。颜色按深度在 4 种颜色之间循环，便于快速区分嵌套层级。</p><p>典型的构建树可能如下所示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>make -j8</span></span>
<span class="line"><span>├── gcc -c main.c -o main.o</span></span>
<span class="line"><span>│   └── as -o main.o /tmp/ccXXXX.s</span></span>
<span class="line"><span>├── gcc -c util.c -o util.o</span></span>
<span class="line"><span>│   └── as -o util.o /tmp/ccYYYY.s</span></span>
<span class="line"><span>└── gcc main.o util.o -o app</span></span>
<span class="line"><span>    └── ld -o app main.o util.o -lc</span></span></code></pre></div><p>每个节点显示进程的命令行，子节点为该进程派生的子进程。树结构由实际的进程拦截构建而成，因此完全反映构建过程中的真实行为。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h2><ul><li><strong>理解构建编排</strong> -- 查看构建系统如何调度编译器、汇编器和链接器。</li><li><strong>调试异常进程派生</strong> -- 识别构建中未预期的进程调用。</li><li><strong>验证拦截完整性</strong> -- 确认所有预期的编译操作都被 catter 正确拦截。</li></ul>`,14)])])}const u=t(i,[["render",o]]);export{m as __pageData,u as default};
